package com.example.countnumber.data
enum class LayoutMode { GRID, SCATTERED }
data class GameSettings( val rounds: Int = 5, val maxCount: Int = 10, val voiceEnabled: Boolean = true, val layoutMode: LayoutMode = LayoutMode.GRID, val language: AppLanguage = AppLanguage.CHINESE )

package com.example.countnumber.data

enum class LayoutMode { GRID, SCATTERED }

enum class VoiceMode { NONE, NUMBER, NUMBER_WITH_ANIMAL }

data class GameSettings(
    val rounds: Int = 5,
    val maxCount: Int = 10,
    val voiceMode: VoiceMode = VoiceMode.NUMBER,
    val layoutMode: LayoutMode = LayoutMode.GRID,
    val language: AppLanguage = AppLanguage.CHINESE
)

package com.example.countnumber.tts

import android.content.Context
import android.speech.tts.TextToSpeech
import com.example.countnumber.data.AppLanguage
import java.util.Locale

class TtsManager(context: Context) {

    private var tts: TextToSpeech? = null
    private var ready = false

    init {
        tts = TextToSpeech(context) { status ->
            ready = status == TextToSpeech.SUCCESS
        }
    }

    fun speak(number: Int, lang: AppLanguage) {
        if (!ready) return
        val locale = localeFor(lang)
        tts?.language = locale
        tts?.speak(number.toString(), TextToSpeech.QUEUE_FLUSH, null, null)
    }

    fun speakText(text: String, lang: AppLanguage) {
        if (!ready) return
        val locale = localeFor(lang)
        tts?.language = locale
        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, null)
    }

    fun speakFeedback(correct: Boolean, lang: AppLanguage) {
        val text = when (lang) {
            AppLanguage.CHINESE -> if (correct) "答對了" else "不對哦"
            AppLanguage.ENGLISH -> if (correct) "Correct!" else "Wrong!"
            AppLanguage.JAPANESE -> if (correct) "せいかい" else "ざんねん"
        }
        speakText(text, lang)
    }

    fun shutdown() {
        tts?.stop()
        tts?.shutdown()
        tts = null
        ready = false
    }

    private fun localeFor(lang: AppLanguage) = when (lang) {
        AppLanguage.CHINESE -> Locale.TRADITIONAL_CHINESE
        AppLanguage.ENGLISH -> Locale.ENGLISH
        AppLanguage.JAPANESE -> Locale.JAPANESE
    }
}

package com.example.countnumber.tts

import android.content.Context
import android.speech.tts.TextToSpeech
import com.example.countnumber.data.Animal
import com.example.countnumber.data.AppLanguage
import com.example.countnumber.data.VoiceMode
import com.example.countnumber.data.localizedName
import java.util.Locale

class TtsManager(context: Context) {

    private var tts: TextToSpeech? = null
    private var ready = false

    init {
        tts = TextToSpeech(context) { status ->
            ready = status == TextToSpeech.SUCCESS
        }
    }

    fun speakGameCount(number: Int, animal: Animal, lang: AppLanguage, voiceMode: VoiceMode) {
        when (voiceMode) {
            VoiceMode.NONE -> return
            VoiceMode.NUMBER -> speakText(number.toString(), lang)
            VoiceMode.NUMBER_WITH_ANIMAL -> speakText(countPhrase(number, animal, lang), lang)
        }
    }

    fun speakAnimalName(animal: Animal, lang: AppLanguage) {
        speakText(animal.localizedName(lang), lang)
    }

    fun speakText(text: String, lang: AppLanguage) {
        if (!ready) return
        val locale = localeFor(lang)
        tts?.language = locale
        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, null)
    }

    fun speakFeedback(correct: Boolean, lang: AppLanguage) {
        val text = when (lang) {
            AppLanguage.CHINESE -> if (correct) "答對了" else "不對哦"
            AppLanguage.ENGLISH -> if (correct) "Correct!" else "Wrong!"
            AppLanguage.JAPANESE -> if (correct) "せいかい" else "ざんねん"
        }
        speakText(text, lang)
    }

    fun shutdown() {
        tts?.stop()
        tts?.shutdown()
        tts = null
        ready = false
    }

    private fun localeFor(lang: AppLanguage) = when (lang) {
        AppLanguage.CHINESE -> Locale.TRADITIONAL_CHINESE
        AppLanguage.ENGLISH -> Locale.ENGLISH
        AppLanguage.JAPANESE -> Locale.JAPANESE
    }

    private fun countPhrase(number: Int, animal: Animal, lang: AppLanguage) = when (lang) {
        AppLanguage.CHINESE -> "$number 隻${animal.localizedName(lang)}"
        AppLanguage.ENGLISH -> "$number ${animal.localizedName(lang)}"
        AppLanguage.JAPANESE -> "$number ${animal.localizedName(lang)}"
    }
}

package com.example.countnumber.ui.components
import androidx.compose.animation.core.LinearEasing import androidx.compose.animation.core.RepeatMode import androidx.compose.animation.core.animateFloat import androidx.compose.animation.core.infiniteRepeatable import androidx.compose.animation.core.rememberInfiniteTransition import androidx.compose.animation.core.tween import androidx.compose.foundation.clickable import androidx.compose.foundation.interaction.MutableInteractionSource import androidx.compose.material3.Text import androidx.compose.runtime.Composable import androidx.compose.runtime.getValue import androidx.compose.runtime.remember import androidx.compose.ui.Modifier import androidx.compose.ui.draw.rotate import androidx.compose.foundation.layout.offset import androidx.compose.ui.platform.LocalConfiguration import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp import kotlin.random.Random
@Composable fun FloatingAnimal( emoji: String, index: Int, onClick: () -> Unit = {} ) { val config = LocalConfiguration.current val screenW = config.screenWidthDp val screenH = config.screenHeightDp
val startX = remember { Random.nextFloat() * screenW } val startY = remember { Random.nextFloat() * screenH } val duration = remember { 3000 + Random.nextInt(3000) } val bounceDuration = remember { 500 + Random.nextInt(500) } val rotateDuration = remember { 2000 + Random.nextInt(2000) }
val infiniteTransition = rememberInfiniteTransition(label = "animal_$index")
val offsetX by infiniteTransition.animateFloat( initialValue = startX, targetValue = (startX + Random.nextFloat() * 80f - 40f).coerceIn(0f, screenW.toFloat()), animationSpec = infiniteRepeatable( animation = tween(duration, easing = LinearEasing), repeatMode = RepeatMode.Reverse ), label = "offsetX_$index" )
val offsetY by infiniteTransition.animateFloat( initialValue = startY, targetValue = (startY + Random.nextFloat() * 60f - 30f).coerceIn(0f, screenH.toFloat()), animationSpec = infiniteRepeatable( animation = tween(bounceDuration, easing = LinearEasing), repeatMode = RepeatMode.Reverse ), label = "offsetY_$index" )
val rotation by infiniteTransition.animateFloat( initialValue = -15f, targetValue = 15f, animationSpec = infiniteRepeatable( animation = tween(rotateDuration), repeatMode = RepeatMode.Reverse ), label = "rotation_$index" )
Text( text = emoji, fontSize = 36.sp, modifier = Modifier .offset(offsetX.dp, offsetY.dp) .rotate(rotation) .clickable( interactionSource = remember { MutableInteractionSource() }, indication = null // 不顯示點擊漣漪，保持可愛感 ) { onClick() } ) }

package com.example.countnumber.ui.components
import androidx.compose.animation.core.LinearEasing import androidx.compose.animation.core.RepeatMode import androidx.compose.animation.core.animateFloat import androidx.compose.animation.core.infiniteRepeatable import androidx.compose.animation.core.rememberInfiniteTransition import androidx.compose.animation.core.tween import androidx.compose.foundation.clickable import androidx.compose.foundation.interaction.MutableInteractionSource import androidx.compose.material3.Text import androidx.compose.runtime.Composable import androidx.compose.runtime.getValue import androidx.compose.runtime.remember import androidx.compose.ui.Modifier import androidx.compose.ui.draw.rotate import androidx.compose.foundation.layout.offset import androidx.compose.ui.platform.LocalConfiguration import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp import kotlin.random.Random
@Composable fun FloatingAnimal( emoji: String, index: Int, reshuffleKey: Int = 0, onClick: () -> Unit = {} ) { val config = LocalConfiguration.current val screenW = config.screenWidthDp val screenH = config.screenHeightDp
val startX = remember(reshuffleKey) { Random.nextFloat() * screenW } val startY = remember(reshuffleKey) { Random.nextFloat() * screenH } val duration = remember(reshuffleKey) { 3000 + Random.nextInt(3000) } val bounceDuration = remember(reshuffleKey) { 500 + Random.nextInt(500) } val rotateDuration = remember(reshuffleKey) { 2000 + Random.nextInt(2000) }
val infiniteTransition = rememberInfiniteTransition(label = "animal_$index")
val offsetX by infiniteTransition.animateFloat( initialValue = startX, targetValue = (startX + Random.nextFloat() * 80f - 40f).coerceIn(0f, screenW.toFloat()), animationSpec = infiniteRepeatable( animation = tween(duration, easing = LinearEasing), repeatMode = RepeatMode.Reverse ), label = "offsetX_$index" )
val offsetY by infiniteTransition.animateFloat( initialValue = startY, targetValue = (startY + Random.nextFloat() * 60f - 30f).coerceIn(0f, screenH.toFloat()), animationSpec = infiniteRepeatable( animation = tween(bounceDuration, easing = LinearEasing), repeatMode = RepeatMode.Reverse ), label = "offsetY_$index" )
val rotation by infiniteTransition.animateFloat( initialValue = -15f, targetValue = 15f, animationSpec = infiniteRepeatable( animation = tween(rotateDuration), repeatMode = RepeatMode.Reverse ), label = "rotation_$index" )
Text( text = emoji, fontSize = 72.sp, modifier = Modifier .offset(offsetX.dp, offsetY.dp) .rotate(rotation) .clickable( interactionSource = remember { MutableInteractionSource() }, indication = null // 不顯示點擊漣漪，保持可愛感 ) { onClick() } ) }

